class Solution:
    def solveEquation(self, equation: str) -> str:
        left, right = equation.split('=')
        left_terms = left.split()
        right_terms = right.split()
        x_coefficient_left = 0
        constant_left = 0
        x_coefficient_right = 0
        constant_right = 0
        for term in left_terms:
            if term == 'x':
                x_coefficient_left += 1
            else:
                constant_left += int(term)
        for term in right_terms:
            if term == 'x':
                x_coefficient_right += 1
            else:
                constant_right += int(term)
        if x_coefficient_left == x_coefficient_right:
            if constant_left == constant_right:
                return "Infinite solutions"
            else:
                return "No solution"
        else:
            x = (constant_right - constant_left) / (x_coefficient_right - x_coefficient_left)
            return f"x={int(x)}"
